and {Template SAP Host Agent by Zabbix agent 2:sap.agent.cpu.load["{$SAP.AGENT.URI}","{$SAP.AGENT.USER}","{$SAP.AGENT.PASSWORD}","avg5"].last()}>0
and {Template SAP Host Agent by Zabbix agent 2:sap.agent.cpu.load["{$SAP.AGENT.URI}","{$SAP.AGENT.USER}","{$SAP.AGENT.PASSWORD}","avg15"].last()}>0

